FROM jsonb_to_recordset('[{"id": "cap-112-chinese-015", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "甲：花寒懶發鳥慵啼，信馬閑行到日西。何處未春先有思？柳條無力魏王堤。\n―― 白居易〈魏王堤〉\n乙：陰陰溪曲綠交加，小雨翻萍上淺沙。鵝鴨不知春去盡，爭隨流水趁桃花。\n―― 晁沖之〈春日〉\n關於這兩首詩的分析，下列敘述何者最恰當？", "options": ["甲詩描寫清晨春寒料峭的景象", "乙詩描寫春末溪邊所見的景致", "兩詩首二句皆對仗，表達情思", "兩詩皆屬七絕，只有偶句用韻"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 15, "raw_text": "15.\n      甲：花寒懶發鳥慵啼，信馬閑行到日西。何處未春先有思？柳條無力魏王堤。\n                              ―― 白居易〈魏王堤〉\n      乙：陰陰溪曲綠交加，小雨翻萍上淺沙。鵝鴨不知春去盡，爭隨流水趁桃花。\n                               ―― 晁沖之〈春日〉\n      關於這兩首詩的分析，下列敘述何者最恰當？\n      (A)甲詩描寫清晨春寒料峭的景象\n      (B)乙詩描寫春末溪邊所見的景致\n      (C)兩詩首二句皆對仗，表達情思\n      (D)兩詩皆屬七絕，只有偶句用韻\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-016", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "「蓋天下有反覆之小人，亦有反覆之君子。人但知不反覆不足以為小人，庸知不\n反覆亦不足以為君子。蓋小人之反覆也，因風氣勢利之所歸，以為變動；君子之\n反覆也，因學識之層累疊進，以為變動。其反覆同，其所以為反覆者不同。」根\n據這段文字，作者認為「不反覆亦不足以為君子」的原因，最可能是下列何者？", "options": ["小人若洗心革面，一反前非即可成為君子", "為應對小人反覆，不得不改變既有的策略", "順應民心的向背，選擇最適合現況的做法", "隨著所知的增長，會修正自己原本的觀點"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 16, "raw_text": "16. 「蓋天下有反覆之小人，亦有反覆之君子。人但知不反覆不足以為小人，庸知不\n     反覆亦不足以為君子。蓋小人之反覆也，因風氣勢利之所歸，以為變動；君子之\n     反覆也，因學識之層累疊進，以為變動。其反覆同，其所以為反覆者不同。」根\n     據這段文字，作者認為「不反覆亦不足以為君子」的原因，最可能是下列何者？\n     (A)小人若洗心革面，一反前非即可成為君子\n     (B)為應對小人反覆，不得不改變既有的策略\n     (C)順應民心的向背，選擇最適合現況的做法\n     (D)隨著所知的增長，會修正自己原本的觀點\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-017", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "以上是根據聯合國《2019年永續發展目標報告》製作的圖表。下列關於圖表內容\n的推論，何者最不恰當？", "options": ["甲： 82% 的全球女性未曾遭受來自伴侶的身體或性暴力", "乙 ：全球女性在職場上擔任管理職位的比例較男性少", "丙 ：全球女性的參政比例有所提升，但仍為少數", "丁：2018 年至少有30%的20 至24 歲南亞女性結過婚"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17.\n\n\n\n\n      以上是根據聯合國《2019年永續發展目標報告》製作的圖表。下列關於圖表內容\n      的推論，何者最不恰當？\n      (A)甲： 82% 的全球女性未曾遭受來自伴侶的身體或性暴力\n      (B)乙 ：全球女性在職場上擔任管理職位的比例較男性少\n      (C)丙 ：全球女性的參政比例有所提升，但仍為少數\n      (D)丁：2018 年至少有30%的20 至24 歲南亞女性結過婚\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-018", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "「商代人只在上、下午各吃一餐，因為農業社會耕作頗費體力，早上需好好補\n充精力，下午因太陽將西下，無法再工作，不如早睡早起，故不必吃得多。\n春秋晚期以來，隨著牛耕鐵器的廣泛使用，尤其是戰國時代鐵器的普及，生產\n力大大提高。社會的面貌起了很大的變化，人們的生活內容漸漸豐富起來，許\n多人開始在夜間從事非生產性的工作，富人娛樂活動增加，便多一餐以補充體\n力。」根據這段文字，古人從兩餐變成三餐的原因，與下列何者最不相關？", "options": ["社會形態改變", "夜間活動增加", "耕作時間延長", "鐵器廣泛使用"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18. 「商代人只在上、下午各吃一餐，因為農業社會耕作頗費體力，早上需好好補\n     充精力，下午因太陽將西下，無法再工作，不如早睡早起，故不必吃得多。\n     春秋晚期以來，隨著牛耕鐵器的廣泛使用，尤其是戰國時代鐵器的普及，生產\n     力大大提高。社會的面貌起了很大的變化，人們的生活內容漸漸豐富起來，許\n     多人開始在夜間從事非生產性的工作，富人娛樂活動增加，便多一餐以補充體\n     力。」根據這段文字，古人從兩餐變成三餐的原因，與下列何者最不相關？\n     (A)社會形態改變 (B)夜間活動增加 (C)耕作時間延長 (D)鐵器廣泛使用\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-019", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "「傳統布農族社會在舉行重大的祭儀活動前，族人會聚集在一起用木杵搗米準備\n製作小米酒，發現不同的木杵會產生不同的聲響，因而將其作為合奏的樂器。後\n來每當族人聽到杵音傳來，就知道最近聚落即將舉辦慶典，杵音也因而具有傳遞\n訊息的功能。」根據這段文字，下列關於傳統布農族社會的推論，何者最恰當？", "options": ["舉行重大慶典需要小米酒", "透過傳遞木杵來交換訊息", "依祭儀種類飲用不同的米酒", "以整齊的杵音宣告祭儀開始"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 19, "raw_text": "19. 「傳統布農族社會在舉行重大的祭儀活動前，族人會聚集在一起用木杵搗米準備\n     製作小米酒，發現不同的木杵會產生不同的聲響，因而將其作為合奏的樂器。後\n     來每當族人聽到杵音傳來，就知道最近聚落即將舉辦慶典，杵音也因而具有傳遞\n     訊息的功能。」根據這段文字，下列關於傳統布農族社會的推論，何者最恰當？\n     (A)舉行重大慶典需要小米酒    (B)透過傳遞木杵來交換訊息\n     (C)依祭儀種類飲用不同的米酒   (D)以整齊的杵音宣告祭儀開始\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-020", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "蘇軾〈西江月〉：「世事一場大夢，人生幾度新涼？夜來風葉已鳴廊，看取眉\n頭鬢上。    酒賤常愁客少，月明多被雲妨。中秋誰與共孤光，把盞淒然北\n望。」下列關於詞句的說明，何者最不恰當？", "options": ["「看取眉頭鬢上」表達自己年華老去", "「酒賤常愁客少」意謂難以維持生計", "「月明多被雲妨」比喻美好的事物不可能長久", "「中秋誰與共孤光」流露想與親友團聚的心願"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 20, "raw_text": "20. 蘇軾〈西江月〉：「世事一場大夢，人生幾度新涼？夜來風葉已鳴廊，看取眉\n    頭鬢上。    酒賤常愁客少，月明多被雲妨。中秋誰與共孤光，把盞淒然北\n    望。」下列關於詞句的說明，何者最不恰當？\n    (A)「看取眉頭鬢上」表達自己年華老去\n    (B)「酒賤常愁客少」意謂難以維持生計\n    (C)「月明多被雲妨」比喻美好的事物不可能長久\n    (D)「中秋誰與共孤光」流露想與親友團聚的心願\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-021", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "1866 至1900 年甲國茶葉出口歐洲略表    單位：萬擔\n年分       出口總額        年分        出口總額\n1866      120        1886       240\n1869      150        1889       187\n1872      170        1892       162\n1879      198        1897       153\n1882      201        1900       120\n說明：\n1866 至1886 年間，甲國茶葉出口逐年大幅增長。歐洲國家茶葉生產技術\n發展起來後，甲國茶葉出口總額急轉直下。從1886 至1900 的十五年間，甲國\n茶葉出口銳減，在歐洲茶葉市場的占有率也從原本幾乎100%，急遽下降至\n10% 左右。\n根據這份表格及說明，可以推論出下列何者？", "options": ["甲國的茶葉生產技術在1886 年後越來越差", "1900 年歐洲茶葉市場總交易量較1886 年少", "1900 年甲國茶葉出口歐洲總額衰退至1886 年的 50%", "1866 至1900 年間，甲國從茶葉出口國變成茶葉進口國"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21.\n                  1866 至1900 年甲國茶葉出口歐洲略表    單位：萬擔\n           年分       出口總額        年分        出口總額\n           1866      120        1886       240\n           1869      150        1889       187\n           1872      170        1892       162\n           1879      198        1897       153\n           1882      201        1900       120\n      說明：\n          1866 至1886 年間，甲國茶葉出口逐年大幅增長。歐洲國家茶葉生產技術\n      發展起來後，甲國茶葉出口總額急轉直下。從1886 至1900 的十五年間，甲國\n      茶葉出口銳減，在歐洲茶葉市場的占有率也從原本幾乎100%，急遽下降至\n      10% 左右。\n      根據這份表格及說明，可以推論出下列何者？\n      (A)甲國的茶葉生產技術在1886 年後越來越差\n      (B)1900 年歐洲茶葉市場總交易量較1886 年少\n      (C)1900 年甲國茶葉出口歐洲總額衰退至1886 年的 50%\n      (D)1866 至1900 年間，甲國從茶葉出口國變成茶葉進口國\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-022", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "「復北上，行石罅中，石峰片片夾起，路宛轉石間，塞者鑿之，陡者級之，斷者\n架木通之，懸者植梯接之。下瞰峭壑陰森，楓松相間，五色紛披，燦若圖繡。\n因念黃山當生平奇覽，而有奇若此，前未一探，茲遊快且愧矣！」根據這段文\n字，下列敘述何者最恰當？", "options": ["作者對自己破壞自然環境感到慚愧", "黃山片片石峰色彩繽紛，有如織錦", "作者北上舊地重遊，乃因懷念黃山冬季美景", "此遊窺得黃山奇景，作者心中因而喜愧交集"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 22, "raw_text": "22. 「復北上，行石罅中，石峰片片夾起，路宛轉石間，塞者鑿之，陡者級之，斷者\n     架木通之，懸者植梯接之。下瞰峭壑陰森，楓松相間，五色紛披，燦若圖繡。\n     因念黃山當生平奇覽，而有奇若此，前未一探，茲遊快且愧矣！」根據這段文\n     字，下列敘述何者最恰當？\n     (A)作者對自己破壞自然環境感到慚愧\n     (B)黃山片片石峰色彩繽紛，有如織錦\n     (C)作者北上舊地重遊，乃因懷念黃山冬季美景\n     (D)此遊窺得黃山奇景，作者心中因而喜愧交集\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-023", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "往歲士人多尚對偶為文，穆脩、張景輩始為平文，當時謂之古文。穆、張\n嘗同造朝，適見有奔馬踐死一犬，二人各記其事。穆脩曰：「馬逸1，有黃犬\n遇蹄而斃。」張景曰：「有犬死奔馬之下。」時文體新變，二人之語皆拙澀，\n當時已謂之工，傳之至今。\n根據這段文字，關於穆脩、張景針對奔馬踐死一犬的記事，下列敘述何者最恰當？", "options": ["穆脩記事只著眼於犬 ", "張景記事只著眼於馬                  1.逸：奔跑", "二人用語崇尚句式對偶", "二人用語皆為時人稱頌"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 23, "raw_text": "23.\n        往歲士人多尚對偶為文，穆脩、張景輩始為平文，當時謂之古文。穆、張\n      嘗同造朝，適見有奔馬踐死一犬，二人各記其事。穆脩曰：「馬逸1，有黃犬\n      遇蹄而斃。」張景曰：「有犬死奔馬之下。」時文體新變，二人之語皆拙澀，\n      當時已謂之工，傳之至今。\n      根據這段文字，關於穆脩、張景針對奔馬踐死一犬的記事，下列敘述何者最恰當？\n      (A)穆脩記事只著眼於犬\n                                    \n      (B)張景記事只著眼於馬                  1.逸：奔跑\n      (C)二人用語崇尚句式對偶\n      (D)二人用語皆為時人稱頌\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-024", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "「錢塘江石堤為洪濤所激，歲歲摧決。杜偉長為轉運使，人有獻說，自浙江稅場\n以東，移退數里為月堤，以避怒水。眾水工皆以為善，獨一老水工以為不然，\n密諭其黨：『移堤則歲無水患，吾等何所衣食？』眾人樂其利，乃從而和之。\n偉長不悟其計，費以巨萬，而江堤之害仍歲有之。」根據這段文字，下列敘述\n何者最恰當？", "options": ["月堤耗時過久，使杜偉長浪費公帑", "水工們為保生計，阻礙了移堤工程", "老水工深知修築月堤無益於防堵水患", "杜偉長堅持移堤，導致年年發生水患"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 24, "raw_text": "24. 「錢塘江石堤為洪濤所激，歲歲摧決。杜偉長為轉運使，人有獻說，自浙江稅場\n     以東，移退數里為月堤，以避怒水。眾水工皆以為善，獨一老水工以為不然，\n     密諭其黨：『移堤則歲無水患，吾等何所衣食？』眾人樂其利，乃從而和之。\n     偉長不悟其計，費以巨萬，而江堤之害仍歲有之。」根據這段文字，下列敘述\n     何者最恰當？\n     (A)月堤耗時過久，使杜偉長浪費公帑\n     (B)水工們為保生計，阻礙了移堤工程\n     (C)老水工深知修築月堤無益於防堵水患\n     (D)杜偉長堅持移堤，導致年年發生水患\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-025", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據本詩，下列敘述何者最恰當？", "options": ["第一節顯示車行至八堵之後天氣不佳", "第二節說明作者此行目的地是暖暖", "第三節可看出那那社名稱的由來", "第四節點出作者珍惜當下的心境"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-25", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 25, "raw_text": "25. 根據本詩，下列敘述何者最恰當？\n    (A)第一節顯示車行至八堵之後天氣不佳\n    (B)第二節說明作者此行目的地是暖暖\n    (C)第三節可看出那那社名稱的由來\n    (D)第四節點出作者珍惜當下的心境\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-026", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "關於本詩的寫作手法，下列敘述何者錯誤？", "options": ["以天氣的變化象徵越來越沉重的心情", "以重複出現的字詞形成詩歌的韻律", "運用諧音及詞義的雙關增添詩意", "預想尚未發生的情景收束全詩"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-25", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 26, "raw_text": "26. 關於本詩的寫作手法，下列敘述何者錯誤？\n    (A)以天氣的變化象徵越來越沉重的心情\n    (B)以重複出現的字詞形成詩歌的韻律\n    (C)運用諧音及詞義的雙關增添詩意\n    (D)預想尚未發生的情景收束全詩\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-027", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據圖文，下列關於跳水比賽的敘述，何者最恰當？", "options": ["入水時水花的大小會影響分數高低", "史上第一場跳水比賽是在室內舉行", "奧運比賽的雙人賽必須配置7名評審", "使用跳板起跳就可以獲得比較高的分數"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-27", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 27, "raw_text": "27. 根據圖文，下列關於跳水比賽的敘述，何者最恰當？\n    (A)入水時水花的大小會影響分數高低 (B)史上第一場跳水比賽是在室內舉行\n    (C)奧運比賽的雙人賽必須配置7名評審 (D)使用跳板起跳就可以獲得比較高的分數\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-028", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據圖文，下列關於跳水比賽規則的敘述，何者最恰當？", "options": ["毋須採計每一跳的得分，可擇優計算最後成績", "選手完成一次跳水，每名評審最高只能給 10 分", "若完成的動作比預定的難度更高，分數也會越高", "選手每一跳須完成的難度係數，由現場抽籤決定"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-27", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 28, "raw_text": "28. 根據圖文，下列關於跳水比賽規則的敘述，何者最恰當？\n    (A)毋須採計每一跳的得分，可擇優計算最後成績\n    (B)選手完成一次跳水，每名評審最高只能給 10 分\n    (C)若完成的動作比預定的難度更高，分數也會越高\n    (D)選手每一跳須完成的難度係數，由現場抽籤決定\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
