FROM jsonb_to_recordset('[{"id": "cap-112-chinese-029", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "亞當是奧運跳水個人賽選手，他在比賽時某次的動作難度係數是 3.0，當他完成\n後，評審團給的分數表如下：\n評審一           評審二     評審三 評審四         評審五          評審六 評審七\n7分           8分     8分  7分           9分          7分  9分\n根據圖文，亞當此次跳水得分的計算方式應是下列何者？\n(A) ( 7 + 7 + 7 ) × 3.0       (B) ( 7 + 7 + 8 ) × 3.0\n(C) ( 7 + 8 + 8 ) × 3.0       (D) ( 8 + 7 + 9 ) × 3.0", "options": ["", "", "", ""], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-27", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 29, "raw_text": "29. 亞當是奧運跳水個人賽選手，他在比賽時某次的動作難度係數是 3.0，當他完成\n    後，評審團給的分數表如下：\n      評審一           評審二     評審三 評審四         評審五          評審六 評審七\n         7分           8分     8分  7分           9分          7分  9分\n    根據圖文，亞當此次跳水得分的計算方式應是下列何者？\n    (A) ( 7 + 7 + 7 ) × 3.0       (B) ( 7 + 7 + 8 ) × 3.0\n    (C) ( 7 + 8 + 8 ) × 3.0       (D) ( 8 + 7 + 9 ) × 3.0\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-030", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "文中「活著的時候就心甘情願把自己埋進納骨塔」的涵義，與下列何者最接近？", "options": ["獲得精神食糧，沉浸書堆", "倡導終身學習，推廣閱讀", "喪失生命熱情，心如死灰", "甘心隱姓埋名，不慕榮利"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-30", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 30, "raw_text": "30. 文中「活著的時候就心甘情願把自己埋進納骨塔」的涵義，與下列何者最接近？\n    (A)獲得精神食糧，沉浸書堆   (B)倡導終身學習，推廣閱讀\n    (C)喪失生命熱情，心如死灰   (D)甘心隱姓埋名，不慕榮利\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-031", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "關於本文的寫作手法，下列敘述何者最恰當？", "options": ["藉由宏偉的建築，對比個人的渺小", "以不同年齡層的閱讀習慣，凸顯世代差異", "將靜態的閱讀比擬為交談，產生動態的效果", "視線推移自室內延伸至室外，強調知識的寬廣 請閲讀以下兩篇短文，並回答32 ～ 33題： 【甲】 1968 年霍普創辦月球大使館公司，推出購買月球土地的服務，只要19.99美元 就能買下月球上的一英畝土地。這間位於內華達州的公司宣稱握有好幾個星體的土 地產權。 霍普創立公司時正值失業、離婚，一切都糟透了。當時他想，如果他有土地，狀 況或許會好一點。霍普回憶：「接著我看到了月亮，我想著，那裡有好多土地啊。」 於是霍普調查《外太空條約》，發現條約僅明文禁止地球的國家主張其他星球 的土地所有權，卻未規範私營公司。在當時，沒人想到會有公司這麼做。於是霍普 飛奔去跑流程，而且從未有任何地球政府挑戰他販賣外太空地產的權限。 —— 改寫自樂羽嘉〈你真的能買下月球的土地嗎？〉 【乙】 1969 年美國太空人阿姆斯壯在月球上踏出人類的第一步，在此之前的兩年， 聯合國大會才通過《外太空條約》並開放各國簽署，至今已有超過 100 個國家簽 署。條約規定必須和平進行太空探索，並造福所有國家。此條約也提到，所有的締 約國都不可以主張天體的所有權，並要求締約國不可破壞他國的探測器或基地，例 如不能降落在這些物體之上或附近。但這也產生了漏洞，讓國家或私人企業能以先 占先贏的手段獨占有利的地點。 2016 年，美國天文物理學家艾維斯在《太空政策》期刊上提到：國家或私人 企業都不能主張月球土地的所有權，否則將會引發「瓜分月球」效應，在某些方 面就像 1880 年代許多國家開始「瓜分非洲」，在剛果爭相主張礦物資源的所有權 一樣。 —— 改寫自曼恩〈月球土地先占先贏〉"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-30", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 31, "raw_text": "31. 關於本文的寫作手法，下列敘述何者最恰當？\n    (A)藉由宏偉的建築，對比個人的渺小\n    (B)以不同年齡層的閱讀習慣，凸顯世代差異\n    (C)將靜態的閱讀比擬為交談，產生動態的效果\n    (D)視線推移自室內延伸至室外，強調知識的寬廣\n\n\n請閲讀以下兩篇短文，並回答32 ～ 33題：\n【甲】\n  1968 年霍普創辦月球大使館公司，推出購買月球土地的服務，只要19.99美元\n就能買下月球上的一英畝土地。這間位於內華達州的公司宣稱握有好幾個星體的土\n地產權。\n  霍普創立公司時正值失業、離婚，一切都糟透了。當時他想，如果他有土地，狀\n況或許會好一點。霍普回憶：「接著我看到了月亮，我想著，那裡有好多土地啊。」\n  於是霍普調查《外太空條約》，發現條約僅明文禁止地球的國家主張其他星球\n的土地所有權，卻未規範私營公司。在當時，沒人想到會有公司這麼做。於是霍普\n飛奔去跑流程，而且從未有任何地球政府挑戰他販賣外太空地產的權限。\n                —— 改寫自樂羽嘉〈你真的能買下月球的土地嗎？〉\n【乙】\n  1969 年美國太空人阿姆斯壯在月球上踏出人類的第一步，在此之前的兩年，\n聯合國大會才通過《外太空條約》並開放各國簽署，至今已有超過 100 個國家簽\n署。條約規定必須和平進行太空探索，並造福所有國家。此條約也提到，所有的締\n約國都不可以主張天體的所有權，並要求締約國不可破壞他國的探測器或基地，例\n如不能降落在這些物體之上或附近。但這也產生了漏洞，讓國家或私人企業能以先\n占先贏的手段獨占有利的地點。\n  2016 年，美國天文物理學家艾維斯在《太空政策》期刊上提到：國家或私人\n企業都不能主張月球土地的所有權，否則將會引發「瓜分月球」效應，在某些方\n面就像 1880 年代許多國家開始「瓜分非洲」，在剛果爭相主張礦物資源的所有權\n一樣。\n                       —— 改寫自曼恩〈月球土地先占先贏〉\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-032", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據甲、乙兩文，下列敘述何者最恰當？", "options": ["1880年代剛果曾提出瓜分非洲礦產的主張", "月球大使館公司成立時，人類尚未踏上月球", "沒人能挑戰霍普販賣月球地產是因《太空政策》期刊的論文", "國家需實際登陸月球後，方可成為《外太空條約》的締約國"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 32, "raw_text": "32. 根據甲、乙兩文，下列敘述何者最恰當？\n    (A)1880年代剛果曾提出瓜分非洲礦產的主張\n    (B)月球大使館公司成立時，人類尚未踏上月球\n    (C)沒人能挑戰霍普販賣月球地產是因《太空政策》期刊的論文\n    (D)國家需實際登陸月球後，方可成為《外太空條約》的締約國\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-033", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "小貞讀過甲、乙兩文後，發現甲文中的霍普與乙文中的艾維斯對某項議題有\n歧見，這項議題最可能是下列何者？", "options": ["太空探索是否應以和平進行為原則", "國家是否可以獨占有利的登月地點", "私人是否可以主張月球土地的所有權", "非締約國是否可以破壞他國的探測器"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 33, "raw_text": "33. 小貞讀過甲、乙兩文後，發現甲文中的霍普與乙文中的艾維斯對某項議題有\n    歧見，這項議題最可能是下列何者？\n    (A)太空探索是否應以和平進行為原則\n    (B)國家是否可以獨占有利的登月地點\n    (C)私人是否可以主張月球土地的所有權\n    (D)非締約國是否可以破壞他國的探測器\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-034", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據本文，下列敘述何者最恰當？", "options": ["「智慧家庭」的數據資料庫能保護網路隱私", "網路上的瀏覽紀錄、按讚喜好具有商業價值", "只要設好高強度的密碼，就不用擔心個資外洩", "「優化人工智慧」是指電腦全面取代人類工作"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-34", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 34, "raw_text": "34. 根據本文，下列敘述何者最恰當？\n    (A)「智慧家庭」的數據資料庫能保護網路隱私\n    (B)網路上的瀏覽紀錄、按讚喜好具有商業價值\n    (C)只要設好高強度的密碼，就不用擔心個資外洩\n    (D)「優化人工智慧」是指電腦全面取代人類工作\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-035", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "下列何者最符合本文的觀點？", "options": ["廣告客製化意謂著消費者主導了市場走向", "生活中使用網路服務，其實是用隱私換來的", "企業與政府受到輿論壓力而開始保護個人資料", "科技日新月異，可以保護我們的隱私不受侵犯"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-34", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 35, "raw_text": "35. 下列何者最符合本文的觀點？\n    (A)廣告客製化意謂著消費者主導了市場走向\n    (B)生活中使用網路服務，其實是用隱私換來的\n    (C)企業與政府受到輿論壓力而開始保護個人資料\n    (D)科技日新月異，可以保護我們的隱私不受侵犯\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-036", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據本文，拿破崙選擇在巴黎聖母院加冕的原因，最可能是下列何者？", "options": ["仿效查理曼大帝的做法", "承襲歷代法國王室的傳統", "強調自己是新帝國的開創者", "希望由教皇而非蘭斯大主教加冕"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-36", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 36, "raw_text": "36. 根據本文，拿破崙選擇在巴黎聖母院加冕的原因，最可能是下列何者？\n    (A)仿效查理曼大帝的做法\n    (B)承襲歷代法國王室的傳統\n    (C)強調自己是新帝國的開創者\n    (D)希望由教皇而非蘭斯大主教加冕\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-037", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據本文，大衛選擇採用拿破崙為約瑟芬加冕的畫面，原因最可能是下列何者？", "options": ["強調皇后的重要性", "避免損及教廷顏面", "滿足拿破崙的虛榮", "聽從拿破崙的指示"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-36", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 37, "raw_text": "37. 根據本文，大衛選擇採用拿破崙為約瑟芬加冕的畫面，原因最可能是下列何者？\n    (A)強調皇后的重要性\n    (B)避免損及教廷顏面\n    (C)滿足拿破崙的虛榮\n    (D)聽從拿破崙的指示\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-038", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "小銘畫了以下這張〈拿破崙的加冕禮〉的模擬圖，根據本文對雅克路易．大衛\n原畫的描述，小銘的模擬圖與原畫相比後有明顯的錯誤，下列何者最可能是這\n個錯誤？", "options": ["十字架擺放的位置", "拿破崙加冕的對象", "教皇給予祝福的手", "拿破崙母親的出席"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-36", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 38, "raw_text": "38. 小銘畫了以下這張〈拿破崙的加冕禮〉的模擬圖，根據本文對雅克路易．大衛\n    原畫的描述，小銘的模擬圖與原畫相比後有明顯的錯誤，下列何者最可能是這\n    個錯誤？\n\n\n\n\n  (A)十字架擺放的位置\n  (B)拿破崙加冕的對象\n  (C)教皇給予祝福的手\n  (D)拿破崙母親的出席\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-039", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據本文，下列何者最可能是仇鸞與嚴嵩一開始交惡的原因？     1.內：宮廷", "options": ["嚴嵩私下上奏，詆毀仇鸞", "嚴嵩與曾銑結盟，疏遠仇鸞", "仇鸞向皇帝稟告嚴嵩父子的罪行", "仇鸞權位日重，不願嚴嵩仍以子視之"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-39", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 39, "raw_text": "39. 根據本文，下列何者最可能是仇鸞與嚴嵩一開始交惡的原因？     1.內：宮廷\n    (A)嚴嵩私下上奏，詆毀仇鸞\n    (B)嚴嵩與曾銑結盟，疏遠仇鸞\n    (C)仇鸞向皇帝稟告嚴嵩父子的罪行\n    (D)仇鸞權位日重，不願嚴嵩仍以子視之\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-040", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "下列文句的解說，何者最恰當？", "options": ["門者以非詔旨格之：守門者將徐階、李本擋下", "嵩還第，父子對泣：嚴嵩與仇鸞兩人盡釋前嫌", "炳訐鸞陰事，帝追戮之：皇帝認為陸炳毀謗死者，憤而殺之", "遣所乘龍舟過海子召嵩：皇帝以高規格召回嚴嵩，以示禮遇"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-39", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 40, "raw_text": "40. 下列文句的解說，何者最恰當？\n    (A)門者以非詔旨格之：守門者將徐階、李本擋下\n    (B)嵩還第，父子對泣：嚴嵩與仇鸞兩人盡釋前嫌\n    (C)炳訐鸞陰事，帝追戮之：皇帝認為陸炳毀謗死者，憤而殺之\n    (D)遣所乘龍舟過海子召嵩：皇帝以高規格召回嚴嵩，以示禮遇\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-041", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "根據本文，關於梁王與楊朱的敘述，下列何者最恰當？", "options": ["梁王認為治理天下應重視禮樂之道", "梁王質疑楊朱是否具有治理天下的能力", "楊朱貶抑堯、舜，能治天下卻不能牧羊", "楊朱以牧羊為例，說明治天下須從小事做起"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-41", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 41, "raw_text": "41. 根據本文，關於梁王與楊朱的敘述，下列何者最恰當？\n    (A)梁王認為治理天下應重視禮樂之道\n    (B)梁王質疑楊朱是否具有治理天下的能力\n    (C)楊朱貶抑堯、舜，能治天下卻不能牧羊\n    (D)楊朱以牧羊為例，說明治天下須從小事做起\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-112-chinese-042", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-112-chinese", "question_type": "single_choice", "question_text": "下列文句，何者最能呼應文中「吞舟之魚，不游支流；鴻鵠高飛，不集汙池」\n的涵義？", "options": ["狡兔死，良狗烹；高鳥盡，良弓藏", "高飛之鳥，死於美食；深泉之魚，死於芳餌", "騏驥千里，一日而達；駑馬十駕，旬亦至之", "剖三寸之蚌，難得明月之珠；探枳棘之巢，難求鳳凰之雛 14      試題結束"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-112-chinese-passage-41", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "d20b649a6a5c", "answer_pdf_sha1": "16ca7e0abba6", "flags": [], "parse_confidence": 1.0, "original_question_number": 42, "raw_text": "42. 下列文句，何者最能呼應文中「吞舟之魚，不游支流；鴻鵠高飛，不集汙池」\n    的涵義？\n    (A)狡兔死，良狗烹；高鳥盡，良弓藏\n    (B)高飛之鳥，死於美食；深泉之魚，死於芳餌\n    (C)騏驥千里，一日而達；駑馬十駕，旬亦至之\n    (D)剖三寸之蚌，難得明月之珠；探枳棘之巢，難求鳳凰之雛\n\n\n\n\n                       14      試題結束\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
